import React, { useEffect, useState, useMemo, useRef } from 'react';
import axios from 'axios';
import Header from './Header';
import * as XLSX from 'xlsx';
import { FaSearch, FaEllipsisV, FaFileExcel, FaBoxOpen, FaTags, FaBarcode, FaWeightHanging, FaMapMarkerAlt, FaCheckCircle } from 'react-icons/fa';

const API_URL = 'https://rrgold.loyalstring.co.in/api/ProductMaster/GetAllLabeledStock';
const PAGE_SIZE = 25;

const Inventory = ({ clientCode }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [labels, setLabels] = useState([]);
  const [search, setSearch] = useState('');
  const [filters, setFilters] = useState({});
  const [page, setPage] = useState(1);
  const searchInputRef = useRef(null);
  const [selectedRows, setSelectedRows] = useState([]);

  useEffect(() => {
    if (!clientCode) return;
    setLoading(true);
    setError('');
    axios.post(API_URL, { ClientCode: clientCode })
      .then(res => {
        if (Array.isArray(res.data)) {
          setLabels(res.data);
        } else if (res.data && Array.isArray(res.data.Data)) {
          setLabels(res.data.Data);
        } else {
          setLabels([]);
        }
      })
      .catch(err => {
        setError(err.response?.data?.Message || 'Failed to fetch label list');
      })
      .finally(() => setLoading(false));
  }, [clientCode]);

  // Filtering and searching
  const filteredLabels = useMemo(() => {
    let data = labels;
    // Search
    if (search) {
      const s = search.toLowerCase();
      data = data.filter(l =>
        (l.ItemCode && l.ItemCode.toLowerCase().includes(s)) ||
        (l.ProductName && l.ProductName.toLowerCase().includes(s)) ||
        (l.BranchName && l.BranchName.toLowerCase().includes(s))
      );
    }
    // Column filters
    Object.entries(filters).forEach(([key, value]) => {
      if (value) {
        data = data.filter(l => (l[key] || '').toString().toLowerCase().includes(value.toLowerCase()));
      }
    });
    return data;
  }, [labels, search, filters]);

  // Pagination
  let paginatedLabels = filteredLabels;
  let totalPages = 1;
  if (!search) {
    totalPages = Math.ceil(filteredLabels.length / PAGE_SIZE);
    paginatedLabels = filteredLabels.slice((page - 1) * PAGE_SIZE, page * PAGE_SIZE);
  }

  // Unique values for filters
  const getUnique = (key) => [...new Set(labels.map(l => l[key]).filter(Boolean))];

  // Handle filter change
  const handleFilterChange = (key, value) => {
    setFilters(f => ({ ...f, [key]: value }));
    setPage(1);
  };

  // Handle search change
  const handleSearchChange = (e) => {
    setSearch(e.target.value);
    setPage(1);
  };

  // Handle page change
  const handlePageChange = (newPage) => {
    if (newPage >= 1 && newPage <= totalPages) setPage(newPage);
  };

  // Export to Excel
  const handleExport = () => {
    const exportData = filteredLabels.map(({ Id, ...rest }) => rest); // Remove Id if not needed
    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'Inventory');
    XLSX.writeFile(wb, 'inventory.xlsx');
  };

  // Selection state
  const allSelected = paginatedLabels.length > 0 && paginatedLabels.every(l => selectedRows.includes(l.Id));
  const toggleSelectAll = () => {
    if (allSelected) setSelectedRows(selectedRows.filter(id => !paginatedLabels.some(l => l.Id === id)));
    else setSelectedRows([...new Set([...selectedRows, ...paginatedLabels.map(l => l.Id)])]);
  };
  const toggleSelectRow = (id) => {
    setSelectedRows(selectedRows.includes(id) ? selectedRows.filter(i => i !== id) : [...selectedRows, id]);
  };

  return (
    <div style={{ minHeight: '100vh', background: '#f7f8fa' }}>
      <Header userInfo={{ ClientCode: clientCode }} />
      <div className="container py-4" style={{ maxWidth: 1300 }}>
        {/* Title */}
        <div className="text-center mb-4">
          <h2 style={{ fontWeight: 800, color: '#222', fontSize: '2.2rem', letterSpacing: 0.5, marginBottom: 0 }}>Inventory Labelled List</h2>
        </div>
        {/* Top bar */}
        <div className="d-flex flex-wrap align-items-center justify-content-between mb-4 gap-2" style={{ background: '#fff', borderRadius: 14, boxShadow: '0 2px 12px #0001', padding: '20px 28px', maxWidth: 1200, margin: '0 auto' }}>
          <div className="d-flex align-items-center gap-2" style={{ flex: 1, minWidth: 320 }}>
            <div style={{ position: 'relative', width: 280 }}>
              <input
                ref={searchInputRef}
                type="text"
                className="form-control ps-5"
                style={{ borderRadius: 10, background: '#f7f8fa', border: '1.5px solid #e0e0e0', height: 44, fontSize: '1.08rem' }}
                placeholder="Search..."
                value={search}
                onChange={handleSearchChange}
              />
              <span style={{ position: 'absolute', left: 16, top: '50%', transform: 'translateY(-50%)', color: '#b0b0b0', fontSize: 20 }}>
                <FaSearch />
              </span>
            </div>
          </div>
          <div className="d-flex align-items-center gap-2">
            <button
              className="btn btn-outline-success d-flex align-items-center"
              style={{ borderRadius: 10, fontWeight: 600, height: 44, fontSize: '1.08rem', border: '1.5px solid #22bb33', background: '#fff', padding: '0 22px' }}
              onClick={handleExport}
            >
              <FaFileExcel className="me-2" /> Export
            </button>
          </div>
        </div>
        {/* Table */}
        <div className="d-flex justify-content-center">
          <div className="table-responsive" style={{ maxWidth: '1200px', minHeight: '60vh', margin: '0 auto', borderRadius: 18, overflow: 'hidden', boxShadow: '0 6px 32px #0002', background: '#fff', border: '1.5px solid #e0e0e0', padding: '0 0 16px 0' }}>
            <table className="table align-middle mb-0" style={{ width: '100%', background: '#fff', borderRadius: 18, overflow: 'hidden', borderCollapse: 'separate', borderSpacing: 0, fontSize: '1.12rem' }}>
              <thead style={{ position: 'sticky', top: 0, zIndex: 2, background: '#fff', borderTopLeftRadius: 18, borderTopRightRadius: 18, boxShadow: '0 2px 8px #0001' }}>
                <tr style={{ borderRadius: 18, height: 60 }}>
                  <th style={{ width: 40, background: '#fff', border: 'none', padding: '0 10px' }}>
                    <input type="checkbox" checked={allSelected} onChange={toggleSelectAll} />
                  </th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', borderTopLeftRadius: 18, fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 180 }}>
                    Product Name
                    <select className="form-select form-select-sm mt-2" style={{ minWidth: 120 }} value={filters.ProductName || ''} onChange={e => handleFilterChange('ProductName', e.target.value)}>
                      <option value="">All</option>
                      {getUnique('ProductName').map(val => <option key={val} value={val}>{val}</option>)}
                    </select>
                  </th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>
                    Category
                    <select className="form-select form-select-sm mt-2" style={{ minWidth: 100 }} value={filters.CategoryName || ''} onChange={e => handleFilterChange('CategoryName', e.target.value)}>
                      <option value="">All</option>
                      {getUnique('CategoryName').map(val => <option key={val} value={val}>{val}</option>)}
                    </select>
                  </th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>
                    SKU
                    <select className="form-select form-select-sm mt-2" style={{ minWidth: 100 }} value={filters.ItemCode || ''} onChange={e => handleFilterChange('ItemCode', e.target.value)}>
                      <option value="">All</option>
                      {getUnique('ItemCode').map(val => <option key={val} value={val}>{val}</option>)}
                    </select>
                  </th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>
                    Gross Wt
                    <select className="form-select form-select-sm mt-2" style={{ minWidth: 100 }} value={filters.GrossWt || ''} onChange={e => handleFilterChange('GrossWt', e.target.value)}>
                      <option value="">All</option>
                      {getUnique('GrossWt').map(val => <option key={val} value={val}>{val}</option>)}
                    </select>
                  </th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>
                    Net Wt
                    <select className="form-select form-select-sm mt-2" style={{ minWidth: 100 }} value={filters.NetWt || ''} onChange={e => handleFilterChange('NetWt', e.target.value)}>
                      <option value="">All</option>
                      {getUnique('NetWt').map(val => <option key={val} value={val}>{val}</option>)}
                    </select>
                  </th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>
                    Branch
                    <select className="form-select form-select-sm mt-2" style={{ minWidth: 100 }} value={filters.BranchName || ''} onChange={e => handleFilterChange('BranchName', e.target.value)}>
                      <option value="">All</option>
                      {getUnique('BranchName').map(val => <option key={val} value={val}>{val}</option>)}
                    </select>
                  </th>
                  <th style={{ fontWeight: 700, color: '#222', background: '#fff', borderTopRightRadius: 18, fontSize: '1.12rem', padding: '16px 14px', border: 'none', minWidth: 120 }}>
                    Status
                    <select className="form-select form-select-sm mt-2" style={{ minWidth: 100 }} value={filters.Status || ''} onChange={e => handleFilterChange('Status', e.target.value)}>
                      <option value="">All</option>
                      {getUnique('Status').map(val => <option key={val} value={val}>{val}</option>)}
                    </select>
                  </th>
                  <th style={{ width: 40, background: '#fff', border: 'none' }}></th>
                </tr>
              </thead>
              <tbody>
                {paginatedLabels.map((label, idx) => (
                  <tr key={label.Id} style={{ background: idx % 2 === 0 ? '#f7f7f7' : '#fff', transition: 'background 0.2s', cursor: 'pointer', borderBottom: '1.5px solid #e0e0e0', height: 60 }}
                    onMouseOver={e => e.currentTarget.style.background = '#f0f0f0'}
                    onMouseOut={e => e.currentTarget.style.background = idx % 2 === 0 ? '#f7f7f7' : '#fff'}
                  >
                    <td style={{ width: 40, border: 'none', padding: '0 10px' }}>
                      <input type="checkbox" checked={selectedRows.includes(label.Id)} onChange={() => toggleSelectRow(label.Id)} />
                    </td>
                    <td style={{ fontWeight: 500, color: '#222', letterSpacing: 0.2, padding: '16px 12px', border: 'none', minWidth: 180 }}>{label.ProductName}</td>
                    <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.CategoryName}</td>
                    <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.ItemCode}</td>
                    <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.GrossWt}</td>
                    <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.NetWt}</td>
                    <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>{label.BranchName}</td>
                    <td style={{ padding: '16px 12px', border: 'none', minWidth: 120 }}>
                      <span className={`badge`} style={{ background: label.Status === 'Active' ? '#e6f9ed' : '#ffeaea', color: label.Status === 'Active' ? '#22bb33' : '#e74c3c', fontWeight: 600, fontSize: '1em', padding: '7px 18px', borderRadius: 16, border: 'none' }}>{label.Status}</span>
                    </td>
                    <td style={{ width: 40, border: 'none', textAlign: 'center' }}>
                      <button className="btn btn-link p-0" style={{ color: '#b0b0b0' }}><FaEllipsisV /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
        {/* Pagination */}
        {totalPages > 1 && !search && (
          <div className="d-flex justify-content-center align-items-center mt-4">
            <nav>
              <ul className="pagination mb-0" style={{ background: '#fff', borderRadius: 10, boxShadow: '0 1px 6px #0001', padding: '10px 24px' }}>
                <li className={`page-item${page === 1 ? ' disabled' : ''}`}><button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1.15rem' }} onClick={() => handlePageChange(page - 1)}>&laquo;</button></li>
                {[...Array(totalPages)].map((_, idx) => (
                  <li key={idx} className={`page-item${page === idx + 1 ? ' active' : ''}`}>
                    <button className="page-link" style={{ border: 'none', background: idx + 1 === page ? '#2563eb' : 'none', color: idx + 1 === page ? '#fff' : '#2563eb', fontWeight: 600, fontSize: '1.15rem', borderRadius: 8, margin: '0 3px', minWidth: 38 }} onClick={() => handlePageChange(idx + 1)}>{idx + 1}</button>
                  </li>
                ))}
                <li className={`page-item${page === totalPages ? ' disabled' : ''}`}><button className="page-link" style={{ border: 'none', background: 'none', color: '#2563eb', fontWeight: 600, fontSize: '1.15rem' }} onClick={() => handlePageChange(page + 1)}>&raquo;</button></li>
              </ul>
            </nav>
          </div>
        )}
      </div>
    </div>
  );
};

export default Inventory;
